import { type InputOptions } from '@actions/core';
export type ILog = {
    getInput(name: string, options?: Readonly<InputOptions>): string;
    setOutput(name: string, value: unknown): void;
    setOutput(name: string, value: unknown): void;
    setFailed(message: string | Readonly<Error>): void;
    isDebug(): boolean;
    debug(message: string): void;
    error(message: string | Readonly<Error>): void;
    warning(message: string | Readonly<Error>): void;
    info(message: string): void;
    log(message: string): void;
    startGroup(name: string): void;
    endGroup(): void;
    group<T>(name: string, fn: () => Promise<T>): Promise<T>;
};
